using System;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;

public static class ReportingFunction
{
    private static readonly string ConnectionString;

    static ReportingFunction()
    {
        var builder = new ConfigurationBuilder()
            .SetBasePath(Environment.CurrentDirectory)
            .AddJsonFile("local.settings.json", optional: true, reloadOnChange: true)
            .AddJsonFile($"{Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT")}.json", optional: true);
        IConfigurationRoot configuration = builder.Build();
        ConnectionString = configuration["SqlConnectionString"];
    }

    [FunctionName("Reporting")]
    public static async System.Threading.Tasks.IActionResult Run(
        [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = "report")] HttpRequest req,
        ILogger log)
    {
        string query = @"
SELECT * FROM Orders
WHERE 1=1";

        var paramsToBeAdded = new List<string>();

        if (req.Query.ContainsKey("customerId"))
        {
            query += " AND CustomerID = @customerId";
            paramsToBeAdded.Add("customerId");
        }

        if (req.Query.ContainsKey("orderDateFrom"))
        {
            query += " AND OrderDate >= @orderDateFrom";
            paramsToBeAdded.Add("orderDateFrom");
        }

        if (req.Query.ContainsKey("orderDateTo"))
        {
            query += " AND OrderDate <= @orderDateTo";
            paramsToBeAdded.Add("orderDateTo");
        }

        var sqlConnection = new SqlConnection(ConnectionString);
        await sqlConnection.OpenAsync();
        using (var command = new SqlCommand(query, sqlConnection))
        {
            foreach (var parameter in paramsToBeAdded)
            {
                command.Parameters.AddWithValue(parameter, req.Query[parameter]);
            }

            var dataTable = new DataTable();
            var adapter = new SqlDataAdapter(command);
            await adapter.Fill(dataTable);

            return new OkObjectResult(dataTable);
        }
    }
